import React, { useEffect, useContext } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { AuthContext } from "../context/AuthContext";
import "./Register.css";

function Register() {
  const navigate = useNavigate();
  const location = useLocation();
  const { user, login } = useContext(AuthContext);

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const tokenFromURL = params.get("token");

    if (tokenFromURL) {
      login(tokenFromURL); // Context-ში ჩაწერა

      // Pending MBTI ტიპი გადაცემა
      const pending = localStorage.getItem("pendingResult");
      const urlType = pending || "DEFAULT"; // თუ არ არის pending
      navigate(`/result?type=${urlType}`, { replace: true });

      // URL-დან token წაშლა
      window.history.replaceState({}, document.title, "/register");
      localStorage.removeItem("google_login_started");
    }
  }, [location, navigate, login]);

  const handleGoogleLogin = () => {
    if (localStorage.getItem("google_login_started")) return;
    localStorage.setItem("google_login_started", "true");
    window.location.href = "http://localhost:5000/auth/google";
  };

  const userPhoto =
    user?.photo?.startsWith("http:")
      ? user.photo.replace("http:", "https:")
      : user?.photo || "/images/default.png";

  return (
    <div className="register-page">
      <div className="register-card">
        <h2 className="register-title">ავტორიზაცია</h2>

        <p className="register-description">
          გაიარე ავტორიზაცია Google ანგარიშით და შეინახე შენი MBTI შედეგები
        </p>

        {!user && (
          <button className="google-signin" onClick={handleGoogleLogin}>
            <img
              src="https://developers.google.com/identity/images/g-logo.png"
              alt="Google"
            />
            Continue with Google
          </button>
        )}

        {user && (
          <div className="register-user-preview">
            <img
              src={userPhoto}
              alt={user.email}
              className="register-user-photo"
              referrerPolicy="no-referrer"
              onError={(e) => (e.target.src = "/images/default.png")}
            />
            <p>მოგესალმებით, {user.name}</p>
          </div>
        )}
      </div>
    </div>
  );
}

export default Register;
